mapper.select:
SELECT aa.id AS attemptId, aa.assessment_id AS assessmentId, a.title AS assessmentTitle, a.course_id AS courseId, c.title AS courseTitle, aa.attempt_no AS attemptNo, aa.score, a.total_score AS totalScore, a.pass_score AS passScore, CASE WHEN aa.passed = 1 THEN TRUE ELSE FALSE END AS passed, aa.status, CASE aa.status WHEN 2 THEN '已交卷' WHEN 3 THEN '已超时提交' ELSE '未知' END AS statusName, aa.started_at AS startedAt, aa.submitted_at AS submittedAt, CASE WHEN aa.started_at IS NULL THEN NULL ELSE TIMESTAMPDIFF( SECOND, aa.started_at, COALESCE(aa.submitted_at, aa.deadline_at) ) END AS durationSeconds FROM assessment_attempt aa INNER JOIN assessment a ON a.id = aa.assessment_id AND a.deleted_at IS NULL INNER JOIN course c ON c.id = a.course_id AND c.deleted_at IS NULL WHERE aa.user_id = #{userId} AND aa.status IN (2, 3)
AND a.course_id = #{query.courseId}
AND aa.passed = 1
AND aa.passed = 0
AND ( a.title LIKE CONCAT('%', #{query.keyword}, '%') OR c.title LIKE CONCAT('%', #{query.keyword}, '%') )
AND aa.submitted_at >= #{query.submittedFrom}
AND aa.submitted_at <= #{query.submittedTo}
ORDER BY COALESCE(aa.submitted_at, aa.deadline_at) DESC, aa.id DESC

SELECT aa.id AS attemptId, a.id AS assessmentId, a.title AS assessmentTitle, a.course_id AS courseId, c.title AS courseTitle, u.id AS userId, u.username, u.real_name AS realName, u.dept_id AS departmentId, d.name AS departmentName, aa.attempt_no AS attemptNo, aa.score, a.total_score AS totalScore, a.pass_score AS passScore, CASE WHEN aa.passed = 1 THEN true ELSE false END AS passed, aa.status, aa.started_at AS startedAt, aa.submitted_at AS submittedAt, CASE WHEN aa.submitted_at IS NOT NULL AND aa.started_at IS NOT NULL THEN TIMESTAMPDIFF(SECOND, aa.started_at, aa.submitted_at) ELSE NULL END AS durationSeconds FROM assessment_attempt aa JOIN assessment a ON a.id = aa.assessment_id AND a.deleted_at IS NULL LEFT JOIN course c ON c.id = a.course_id AND c.deleted_at IS NULL LEFT JOIN user u ON u.id = aa.user_id AND u.deleted_at IS NULL LEFT JOIN department d ON d.id = u.dept_id WHERE 1=1
AND a.id = #{assessmentId}
AND a.course_id = #{courseId}
AND a.category_id = #{categoryId}
AND u.dept_id = #{departmentId}
AND (u.real_name LIKE CONCAT('%', #{keyword}, '%') OR u.username LIKE CONCAT('%', #{keyword}, '%') OR a.title LIKE CONCAT('%', #{keyword}, '%'))
AND aa.passed = 1
AND aa.passed = 0
AND aa.submitted_at >= #{submittedFrom}
AND aa.submitted_at <= #{submittedTo}
ORDER BY aa.submitted_at DESC, aa.id DESC

SELECT COUNT(DISTINCT u.id)
FROM user u
WHERE u.role_type = 1
  AND u.status = 1
  AND u.deleted_at IS NULL
  AND (
      NOT EXISTS (SELECT 1 FROM assessment_question_course aqc
                  JOIN assessment_question aq ON aq.id = aqc.question_id
                  JOIN assessment a ON a.category_id = #{categoryId}
                  WHERE a.course_id = #{courseId}
                    AND aq.category_id = #{categoryId}
                    AND aq.status = 1
                    AND aq.deleted_at IS NULL)
      OR
      u.dept_id IN (
          SELECT cd.department_id FROM course_department cd WHERE cd.course_id = #{courseId}
      )
  )

SELECT u.username, u.real_name AS realName, d.name AS departmentName, a.title AS assessmentTitle, c.title AS courseTitle, aa.attempt_no AS attemptNo, aa.score, a.total_score AS totalScore, a.pass_score AS passScore, CASE WHEN aa.passed = 1 THEN '通过' ELSE '未通过' END AS passedText, aa.started_at AS startedAt, aa.submitted_at AS submittedAt, CASE WHEN aa.submitted_at IS NOT NULL AND aa.started_at IS NOT NULL THEN TIMESTAMPDIFF(SECOND, aa.started_at, aa.submitted_at) ELSE NULL END AS durationSeconds FROM assessment_attempt aa JOIN assessment a ON a.id = aa.assessment_id AND a.deleted_at IS NULL LEFT JOIN course c ON c.id = a.course_id AND c.deleted_at IS NULL LEFT JOIN user u ON u.id = aa.user_id AND u.deleted_at IS NULL LEFT JOIN department d ON d.id = u.dept_id WHERE 1=1
AND a.id = #{assessmentId}
AND a.course_id = #{courseId}
AND a.category_id = #{categoryId}
AND u.dept_id = #{departmentId}
AND (u.real_name LIKE CONCAT('%', #{keyword}, '%') OR u.username LIKE CONCAT('%', #{keyword}, '%') OR a.title LIKE CONCAT('%', #{keyword}, '%'))
AND aa.passed = 1
AND aa.passed = 0
AND aa.submitted_at >= #{submittedFrom}
AND aa.submitted_at <= #{submittedTo}
ORDER BY aa.submitted_at DESC, aa.id DESC
